// 1. Get the website text from the Jina node (Check 'data' or 'content')
// We reference the Jina node directly to get the source text
const jinaData = $('Jina_Scraper').item.json;
const text = jinaData.data || jinaData.content || "";

// 2. The "Regex" pattern to find emails
// This looks for anything like word@word.com
const emailPattern = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9._-]+)/gi;

// 3. Extract all matches
let emails = text.match(emailPattern) || [];

// 4. Clean the list (Remove duplicates and lowercase everything)
emails = [...new Set(emails.map(email => email.toLowerCase()))];

// 5. Remove "junk" files that look like emails (image.png, script.js)
const junkExtensions = ['.png', '.jpg', '.jpeg', '.gif', '.js', '.css', '.svg', '.webp'];
emails = emails.filter(email => !junkExtensions.some(ext => email.endsWith(ext)));

// 6. The "Priority" Sorter
// We want "jane@" BEFORE "info@". 
// If an email starts with these generic words, push it to the back.
const genericPrefixes = ['info', 'contact', 'hello', 'support', 'admin', 'sales', 'enquiries', 'office', 'jobs', 'careers'];

emails.sort((a, b) => {
  const aIsGeneric = genericPrefixes.some(prefix => a.startsWith(prefix));
  const bIsGeneric = genericPrefixes.some(prefix => b.startsWith(prefix));

  if (aIsGeneric && !bIsGeneric) return 1; // b comes first
  if (!aIsGeneric && bIsGeneric) return -1; // a comes first
  return 0;
});

// 7. Output the best email found (or null if none)
return {
  json: {
    ...$input.item.json, // Keep all previous data from the AI/Switch node
    extracted_email: emails.length > 0 ? emails[0] : null, // The #1 best email
    all_emails: emails.join(", "), // A list of all emails found (for reference)
    email_status: emails.length > 0 ? "Found" : "Manual Check Needed"
  }
};

